def basicCalculator(expression):
    res = 0
    sign = 1
    num = ""
    for c in expression:
        if c.isdecimal():
            num += c
            continue
        res += int(num) * sign
        num = ""
        if c == "+":
            sign = 1
        elif c == "-":
            sign = -1
        else:
            raise ValueError(f"Invalid operator {c}")
    return res + int(num) * sign

